120→#[derive(serde::Serialize)]
121→struct EntireLogResult {
122→    lines: Vec<String>,
123→    total_lines: u32,
124→    file_size_bytes: u64,
125→}
126→
127→#[tauri::command]
128→fn get_entire_logs(repo_path: String, tail_lines: u32) -> Result<EntireLogResult, String> {
129→    let log_path = std::path::Path::new(&repo_path).join(".entire/logs/entire.log");
130→    if !log_path.exists() {
131→        return Err("No log file found".to_string());
132→    }
133→
134→    let metadata = std::fs::metadata(&log_path)
135→        .map_err(|e| format!("Failed to read log metadata: {}", e))?;
136→    let file_size_bytes = metadata.len();
137→
138→    let file = std::fs::File::open(&log_path)
139→        .map_err(|e| format!("Failed to open log file: {}", e))?;
140→
141→    // Count total lines
142→    let reader = BufReader::new(&file);
143→    let all_lines: Vec<String> = reader.lines().filter_map(|l| l.ok()).collect();
144→    let total_lines = all_lines.len() as u32;
145→
146→    // Take last N lines
147→    let start = all_lines.len().saturating_sub(tail_lines as usize);
148→    let lines = all_lines[start..].to_vec();
149→
150→    Ok(EntireLogResult {
151→        lines,
152→        total_lines,
153→        file_size_bytes,
154→    })
155→}
