  repoPath: string,
  checkpointId: string,
  sessionIndex: number
) {
  return useQuery<TranscriptMessage[]>({
    queryKey: ["transcript", repoPath, checkpointId, sessionIndex],
    queryFn: () =>
      invoke("get_transcript", { repoPath, checkpointId, sessionIndex }),
    enabled: !!repoPath && !!checkpointId,
    retry: false,
  });
}

